#
# Pass all arguments before 'operation' to cURL except the ones we override
#
take_user=false
take_host=false
take_accept_header=false
take_contenttype_header=false

for key in "$@"; do
# Take the value of -u|--user argument
if [[ "$take_user" = true ]]; then
    basic_auth_credential="$key"
    take_user=false
    continue
fi
# Take the value of --host argument
if [[ "$take_host" = true ]]; then
    host="$key"
    take_host=false
    continue
fi
# Take the value of --accept argument
if [[ "$take_accept_header" = true ]]; then
    header_accept=$(lookup_mime_type "$key")
    take_accept_header=false
    continue
fi
# Take the value of --content-type argument
if [[ "$take_contenttype_header" = true ]]; then
    header_content_type=$(lookup_mime_type "$key")
    take_contenttype_header=false
    continue
fi
case $key in
    -h|--help)
    if [[ "x$operation" == "x" ]]; then
        print_help
        exit 0
    else
        eval "print_${operation}_help"
        exit 0
    fi
    ;;
    -V|--version)
    print_version
    exit 0
    ;;
    --about)
    print_about
    exit 0
    ;;
    -u|--user)
    take_user=true
    ;;
    --host)
    take_host=true
    ;;
    --force)
    force=true
    ;;
    -ac|--accept)
    take_accept_header=true
    ;;
    -ct|--content-type)
    take_contenttype_header=true
    ;;
    --dry-run)
    print_curl=true
    ;;
    -nc|--no-colors)
        RED=""
        GREEN=""
        YELLOW=""
        BLUE=""
        MAGENTA=""
        CYAN=""
        WHITE=""
        BOLD=""
        OFF=""
        result_color_table=( "" "" "" "" "" "" "" )
    ;;
    apiV2AiServiceCompletionsCompleteGet)
    operation="apiV2AiServiceCompletionsCompleteGet"
    ;;
    countCallingCodesByCountryAsync)
    operation="countCallingCodesByCountryAsync"
    ;;
    countCitiesByStateAsync)
    operation="countCitiesByStateAsync"
    ;;
    countCountries)
    operation="countCountries"
    ;;
    countCountryStatesAsync)
    operation="countCountryStatesAsync"
    ;;
    countTimezonesByCountryAsync)
    operation="countTimezonesByCountryAsync"
    ;;
    countTopLevelDomainsByCountryAsync)
    operation="countTopLevelDomainsByCountryAsync"
    ;;
    getAllCountries)
    operation="getAllCountries"
    ;;
    getCallingCodesByCountryIdAsync)
    operation="getCallingCodesByCountryIdAsync"
    ;;
    getCitiesByCountryStateIdAsync)
    operation="getCitiesByCountryStateIdAsync"
    ;;
    getCountryById)
    operation="getCountryById"
    ;;
    getCountryStateByIdAsync)
    operation="getCountryStateByIdAsync"
    ;;
    getCountryStatesAsync)
    operation="getCountryStatesAsync"
    ;;
    getEnabledCurrenciesByCountryIdAsync)
    operation="getEnabledCurrenciesByCountryIdAsync"
    ;;
    getTimeZonesByCountryIdAsync)
    operation="getTimeZonesByCountryIdAsync"
    ;;
    getTopLevelDomainsByCountryIdAsync)
    operation="getTopLevelDomainsByCountryIdAsync"
    ;;
    searchCountriesByNameAsync)
    operation="searchCountriesByNameAsync"
    ;;
    countCurrenciesAsync)
    operation="countCurrenciesAsync"
    ;;
    getCurrencyByIdAsync)
    operation="getCurrencyByIdAsync"
    ;;
    getEnabledCurrenciesAsync)
    operation="getEnabledCurrenciesAsync"
    ;;
    accountLogoutPost)
    operation="accountLogoutPost"
    ;;
    accountManageDownloadPersonalDataPost)
    operation="accountManageDownloadPersonalDataPost"
    ;;
    accountManageLinkExternalLoginPost)
    operation="accountManageLinkExternalLoginPost"
    ;;
    accountPerformExternalLoginPost)
    operation="accountPerformExternalLoginPost"
    ;;
    forgotPasswordPost)
    operation="forgotPasswordPost"
    ;;
    healthGet)
    operation="healthGet"
    ;;
    helloGet)
    operation="helloGet"
    ;;
    loginPost)
    operation="loginPost"
    ;;
    manage2faPost)
    operation="manage2faPost"
    ;;
    manageInfoGet)
    operation="manageInfoGet"
    ;;
    manageInfoPost)
    operation="manageInfoPost"
    ;;
    mapIdentityApiConfirmEmail)
    operation="mapIdentityApiConfirmEmail"
    ;;
    refreshPost)
    operation="refreshPost"
    ;;
    registerPost)
    operation="registerPost"
    ;;
    resendConfirmationEmailPost)
    operation="resendConfirmationEmailPost"
    ;;
    resetPasswordPost)
    operation="resetPasswordPost"
    ;;
    versionGet)
    operation="versionGet"
    ;;
    countLanguagesAsync)
    operation="countLanguagesAsync"
    ;;
    getLanguageByIdAsync)
    operation="getLanguageByIdAsync"
    ;;
    getLanguagesAsync)
    operation="getLanguagesAsync"
    ;;
    apiV2GlobalSystemMigratePost)
    operation="apiV2GlobalSystemMigratePost"
    ;;
    countTimezonesAsync)
    operation="countTimezonesAsync"
    ;;
    getTimeZoneByIdAsync)
    operation="getTimeZoneByIdAsync"
    ;;
    getTimeZonesAsync)
    operation="getTimeZonesAsync"
    ;;
    *==*)
    # Parse body arguments and convert them into top level
    # JSON properties passed in the body content as strings
    if [[ "$operation" ]]; then
        IFS='==' read -r body_key sep body_value <<< "$key"
        body_parameters[${body_key}]="\"${body_value}\""
    fi
    ;;
    --body=*)
    # Parse value of body as argument and convert it into only
    # the raw body content
    if [[ "$operation" ]]; then
        IFS='--body=' read -r body_value <<< "$key"
        body_value=${body_value##--body=}
        body_parameters["RAW_BODY"]="${body_value}"
        RAW_BODY=1
    fi
    ;;
    *:=*)
    # Parse body arguments and convert them into top level
    # JSON properties passed in the body content without quotes
    if [[ "$operation" ]]; then
        # ignore error about 'sep' being unused
        # shellcheck disable=SC2034
        IFS=':=' read -r body_key sep body_value <<< "$key"
        body_parameters[${body_key}]=${body_value}
    fi
    ;;
    +([^=]):*)
    # Parse header arguments and convert them into curl
    # only after the operation argument
    if [[ "$operation" ]]; then
        IFS=':' read -r header_name header_value <<< "$key"
        header_arguments[$header_name]=$header_value
    else
        curl_arguments+=" $key"
    fi
    ;;
    -)
    body_content_temp_file=$(mktemp)
    cat - > "$body_content_temp_file"
    ;;
    *=*)
    # Parse operation arguments and convert them into curl
    # only after the operation argument
    if [[ "$operation" ]]; then
        IFS='=' read -r parameter_name parameter_value <<< "$key"
        if [[ -z "${operation_parameters[$parameter_name]+foo}" ]]; then
            operation_parameters[$parameter_name]=$(url_escape "${parameter_value}")
        else
            operation_parameters[$parameter_name]+=":::"$(url_escape "${parameter_value}")
        fi
    else
        curl_arguments+=" $key"
    fi
    ;;
    *)
    # If we are before the operation, treat the arguments as cURL arguments
    if [[ "x$operation" == "x" ]]; then
        # Maintain quotes around cURL arguments if necessary
        space_regexp="[[:space:]]"
        if [[ $key =~ $space_regexp ]]; then
            curl_arguments+=" \"$key\""
        else
            curl_arguments+=" $key"
        fi
    fi
    ;;
esac
done


# Check if user provided host name
if [[ -z "$host" ]]; then
    ERROR_MSG="ERROR: No hostname provided!!! You have to  provide on command line option '--host ...'"
    exit 1
fi

# Check if user specified operation ID
if [[ -z "$operation" ]]; then
    ERROR_MSG="ERROR: No operation specified!!!"
    exit 1
fi


# Run cURL command based on the operation ID
case $operation in
    apiV2AiServiceCompletionsCompleteGet)
    call_apiV2AiServiceCompletionsCompleteGet
    ;;
    countCallingCodesByCountryAsync)
    call_countCallingCodesByCountryAsync
    ;;
    countCitiesByStateAsync)
    call_countCitiesByStateAsync
    ;;
    countCountries)
    call_countCountries
    ;;
    countCountryStatesAsync)
    call_countCountryStatesAsync
    ;;
    countTimezonesByCountryAsync)
    call_countTimezonesByCountryAsync
    ;;
    countTopLevelDomainsByCountryAsync)
    call_countTopLevelDomainsByCountryAsync
    ;;
    getAllCountries)
    call_getAllCountries
    ;;
    getCallingCodesByCountryIdAsync)
    call_getCallingCodesByCountryIdAsync
    ;;
    getCitiesByCountryStateIdAsync)
    call_getCitiesByCountryStateIdAsync
    ;;
    getCountryById)
    call_getCountryById
    ;;
    getCountryStateByIdAsync)
    call_getCountryStateByIdAsync
    ;;
    getCountryStatesAsync)
    call_getCountryStatesAsync
    ;;
    getEnabledCurrenciesByCountryIdAsync)
    call_getEnabledCurrenciesByCountryIdAsync
    ;;
    getTimeZonesByCountryIdAsync)
    call_getTimeZonesByCountryIdAsync
    ;;
    getTopLevelDomainsByCountryIdAsync)
    call_getTopLevelDomainsByCountryIdAsync
    ;;
    searchCountriesByNameAsync)
    call_searchCountriesByNameAsync
    ;;
    countCurrenciesAsync)
    call_countCurrenciesAsync
    ;;
    getCurrencyByIdAsync)
    call_getCurrencyByIdAsync
    ;;
    getEnabledCurrenciesAsync)
    call_getEnabledCurrenciesAsync
    ;;
    accountLogoutPost)
    call_accountLogoutPost
    ;;
    accountManageDownloadPersonalDataPost)
    call_accountManageDownloadPersonalDataPost
    ;;
    accountManageLinkExternalLoginPost)
    call_accountManageLinkExternalLoginPost
    ;;
    accountPerformExternalLoginPost)
    call_accountPerformExternalLoginPost
    ;;
    forgotPasswordPost)
    call_forgotPasswordPost
    ;;
    healthGet)
    call_healthGet
    ;;
    helloGet)
    call_helloGet
    ;;
    loginPost)
    call_loginPost
    ;;
    manage2faPost)
    call_manage2faPost
    ;;
    manageInfoGet)
    call_manageInfoGet
    ;;
    manageInfoPost)
    call_manageInfoPost
    ;;
    mapIdentityApiConfirmEmail)
    call_mapIdentityApiConfirmEmail
    ;;
    refreshPost)
    call_refreshPost
    ;;
    registerPost)
    call_registerPost
    ;;
    resendConfirmationEmailPost)
    call_resendConfirmationEmailPost
    ;;
    resetPasswordPost)
    call_resetPasswordPost
    ;;
    versionGet)
    call_versionGet
    ;;
    countLanguagesAsync)
    call_countLanguagesAsync
    ;;
    getLanguageByIdAsync)
    call_getLanguageByIdAsync
    ;;
    getLanguagesAsync)
    call_getLanguagesAsync
    ;;
    apiV2GlobalSystemMigratePost)
    call_apiV2GlobalSystemMigratePost
    ;;
    countTimezonesAsync)
    call_countTimezonesAsync
    ;;
    getTimeZoneByIdAsync)
    call_getTimeZoneByIdAsync
    ;;
    getTimeZonesAsync)
    call_getTimeZonesAsync
    ;;
    *)
    ERROR_MSG="ERROR: Unknown operation: $operation"
    exit 1
esac
